const upload = $('Florist uploads photo').item.json.body || {};
const row = $input.first()?.json || {};

const orderId = String(upload.order_id || row.order_id || '').trim();
const photoUrl = String(upload.photo_url || '').trim();
const caption = String(upload.caption || '').trim();
const approvalMinutes = Number(upload.approval_minutes || 20);

if (!orderId || !photoUrl) {
  return [{ json: { statusCode: 400, error: 'order_id and photo_url are required' } }];
}

if (!row.order_id) {
  return [{ json: { statusCode: 404, error: 'Order not found', order_id: orderId } }];
}

const deadline = new Date(Date.now() + approvalMinutes * 60 * 1000).toISOString();
const deliveryUrl = `https://flores.aitechnologiya.ru/delivery.html?order=${encodeURIComponent(orderId)}`;
const approvalNote = [
  `photo_url=${photoUrl}`,
  `approval_deadline=${deadline}`,
  caption ? `caption=${caption}` : '',
].filter(Boolean).join('\n');

return [{
  json: {
    statusCode: 200,
    order_id: orderId,
    telegram_id: row.telegram_id || '',
    telegram_username: row.telegram_username || '',
    customer_name: row.customer_name || '',
    bouquet_name: row.bouquet_name || row.items_text || 'Заказ',
    photo_url: photoUrl,
    caption,
    approval_deadline: deadline,
    delivery_url: deliveryUrl,
    order_status: 'awaiting_client_approval',
    notes: approvalNote,
    message_text: row.message_text || '',
  }
}];

const BOT_TOKEN = $env.TELEGRAM_BOT_TOKEN;
const FLORIST_CHAT_IDS = ['125048853', '435672235'];
const data = $('Prepare approval').item.json;

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

async function telegram(method, body) {
  if (!BOT_TOKEN) throw new Error('TELEGRAM_BOT_TOKEN is not set');
  return await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${BOT_TOKEN}/${method}`,
    body,
    json: true,
  });
}

const clientCaption = [
  '🌸 <b>Ваш букет готов к проверке</b>',
  '',
  `Заказ: <code>${escapeHtml(data.order_id)}</code>`,
  `Букет: ${escapeHtml(data.bouquet_name)}`,
  data.caption ? `Комментарий флориста: ${escapeHtml(data.caption)}` : '',
  '',
  'Пожалуйста, подтвердите фото или попросите изменения.',
].filter(Boolean).join('\n');

const sent = [];

if (data.telegram_id) {
  const result = await telegram.call(this, 'sendPhoto', {
    chat_id: data.telegram_id,
    photo: data.photo_url,
    caption: clientCaption,
    parse_mode: 'HTML',
    reply_markup: {
      inline_keyboard: [[
        { text: '✅ Одобрить', callback_data: `approve:${data.order_id}` },
        { text: '✏️ Нужны изменения', callback_data: `revision:${data.order_id}` },
      ]],
    },
  });
  sent.push({ type: 'client_photo', chat_id: data.telegram_id, ok: result.ok === true });
}

const adminText = [
  '📸 Фото букета отправлено клиенту',
  '',
  `Заказ: ${data.order_id}`,
  `Клиент: ${data.customer_name || '-'}`,
  `Дедлайн автоодобрения: ${data.approval_deadline}`,
].join('\n');

for (const chatId of FLORIST_CHAT_IDS) {
  const result = await telegram.call(this, 'sendMessage', {
    chat_id: chatId,
    text: adminText,
    disable_web_page_preview: true,
  });
  sent.push({ type: 'admin_notice', chat_id: chatId, ok: result.ok === true });
}

return [{ json: { ok: true, order_id: data.order_id, sent } }];
